import{_ as d,o as r,c as a,a3 as e}from"./chunks/framework.CVjg771q.js";const u=JSON.parse('{"title":"五行","description":"金木水火土——不是五种物质，而是五气、五运、五种关系。相生相克之间，藏着中国人理解世界的底层模型。","frontmatter":{"pageClass":"dao-changshi-page","aside":false,"title":"五行","description":"金木水火土——不是五种物质，而是五气、五运、五种关系。相生相克之间，藏着中国人理解世界的底层模型。"},"headers":[],"relativePath":"changshi/wuxing/index.md","filePath":"changshi/wuxing/index.md","lastUpdated":1779783531000}'),h={name:"changshi/wuxing/index.md"};function o(l,t,n,i,b,s){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="五行" tabindex="-1">五行 <a class="header-anchor" href="#五行" aria-label="Permalink to &quot;五行&quot;">​</a></h1><blockquote><p>五行：一曰水，二曰火，三曰木，四曰金，五曰土。 不是五种东西，是五种运动、五种关系、五种气。</p></blockquote><h2 id="相生" tabindex="-1">相生 <a class="header-anchor" href="#相生" aria-label="Permalink to &quot;相生&quot;">​</a></h2><p><strong>木生火，火生土，土生金，金生水，水生木。</strong></p><table tabindex="0"><thead><tr><th>相生</th><th>原理</th></tr></thead><tbody><tr><td>木生火</td><td>木干暖而生火——木材可以燃烧</td></tr><tr><td>火生土</td><td>火焚木而生土——万物焚后归为灰土</td></tr><tr><td>土生金</td><td>土藏矿而生金——金属矿物藏于土中</td></tr><tr><td>金生水</td><td>金凝结而生水——金属表面可凝结水珠</td></tr><tr><td>水生木</td><td>水润泽而生木——水能滋养树木生长</td></tr></tbody></table><h2 id="相克" tabindex="-1">相克 <a class="header-anchor" href="#相克" aria-label="Permalink to &quot;相克&quot;">​</a></h2><p><strong>木克土，土克水，水克火，火克金，金克木。</strong></p><table tabindex="0"><thead><tr><th>相克</th><th>原理</th></tr></thead><tbody><tr><td>木克土</td><td>专胜散——树木扎根可固土</td></tr><tr><td>土克水</td><td>实胜虚——堤坝可阻止水流</td></tr><tr><td>水克火</td><td>众胜寡——大水可熄灭火焰</td></tr><tr><td>火克金</td><td>精胜坚——烈火可熔化金属</td></tr><tr><td>金克木</td><td>刚胜柔——刀具可砍伐树木</td></tr></tbody></table><h2 id="五行总表" tabindex="-1">五行总表 <a class="header-anchor" href="#五行总表" aria-label="Permalink to &quot;五行总表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>五行</th><th>方位</th><th>五色</th><th>五季</th><th>五脏</th><th>五腑</th><th>五官</th><th>五味</th><th>五音</th><th>五常</th></tr></thead><tbody><tr><td>木</td><td>东</td><td>青</td><td>春</td><td>肝</td><td>胆</td><td>眼</td><td>酸</td><td>角</td><td>仁</td></tr><tr><td>火</td><td>南</td><td>赤</td><td>夏</td><td>心</td><td>小肠</td><td>舌</td><td>苦</td><td>徵</td><td>礼</td></tr><tr><td>土</td><td>中</td><td>黄</td><td>长夏</td><td>脾</td><td>胃</td><td>口</td><td>甘</td><td>宫</td><td>信</td></tr><tr><td>金</td><td>西</td><td>白</td><td>秋</td><td>肺</td><td>大肠</td><td>鼻</td><td>辛</td><td>商</td><td>义</td></tr><tr><td>水</td><td>北</td><td>黑</td><td>冬</td><td>肾</td><td>膀胱</td><td>耳</td><td>咸</td><td>羽</td><td>智</td></tr></tbody></table><h2 id="五行与五色、五方位" tabindex="-1">五行与五色、五方位 <a class="header-anchor" href="#五行与五色、五方位" aria-label="Permalink to &quot;五行与五色、五方位&quot;">​</a></h2><p>口诀：<strong>金西白、木东青、水北黑、火南红、土中黄</strong></p><table tabindex="0"><thead><tr><th>五行</th><th>方位</th><th>颜色</th></tr></thead><tbody><tr><td>金</td><td>西</td><td>白、金、银</td></tr><tr><td>木</td><td>东</td><td>青、绿</td></tr><tr><td>水</td><td>北</td><td>黑、蓝、灰</td></tr><tr><td>火</td><td>南</td><td>红、紫、粉</td></tr><tr><td>土</td><td>中</td><td>黄、咖啡、土色</td></tr></tbody></table><h2 id="五行与儒家五常" tabindex="-1">五行与儒家五常 <a class="header-anchor" href="#五行与儒家五常" aria-label="Permalink to &quot;五行与儒家五常&quot;">​</a></h2><table tabindex="0"><thead><tr><th>五行</th><th>五常</th><th>含义</th></tr></thead><tbody><tr><td>金</td><td>义</td><td>刚正、决断、重义气</td></tr><tr><td>木</td><td>仁</td><td>仁慈、同情、恻隐之心</td></tr><tr><td>水</td><td>智</td><td>智慧、灵活、深沉</td></tr><tr><td>火</td><td>礼</td><td>热情、礼貌、文明</td></tr><tr><td>土</td><td>信</td><td>诚信、稳重、厚道</td></tr></tbody></table><blockquote><p>哪一种五行多，就体现出哪一种属性。哪一个五行缺失，就代表不具备这种性质。 例如：命中缺金的人，不太讲「义」；缺木的人，同情心不太强。</p></blockquote><h2 id="五行与中医" tabindex="-1">五行与中医 <a class="header-anchor" href="#五行与中医" aria-label="Permalink to &quot;五行与中医&quot;">​</a></h2><table tabindex="0"><thead><tr><th>五行</th><th>五脏</th><th>五腑</th><th>五官</th></tr></thead><tbody><tr><td>木</td><td>肝</td><td>胆</td><td>眼（肝开窍于眼）</td></tr><tr><td>火</td><td>心</td><td>小肠</td><td>舌（舌为心之官）</td></tr><tr><td>土</td><td>脾</td><td>胃</td><td>口（口唇为脾之官）</td></tr><tr><td>金</td><td>肺</td><td>大肠</td><td>鼻（肺开窍于鼻）</td></tr><tr><td>水</td><td>肾</td><td>膀胱</td><td>耳（肾开窍于耳）</td></tr></tbody></table><p>心肝脾肺肾缺一不可。哪一个过多或缺失，对应的方面就需要多加注意。</p><h2 id="五行与五味" tabindex="-1">五行与五味 <a class="header-anchor" href="#五行与五味" aria-label="Permalink to &quot;五行与五味&quot;">​</a></h2><table tabindex="0"><thead><tr><th>五行</th><th>五味</th><th>原理</th></tr></thead><tbody><tr><td>木</td><td>酸</td><td>木气升发受阻（如肝气郁结）则生酸</td></tr><tr><td>火</td><td>苦</td><td>火气上炎（如心火旺盛）则生苦</td></tr><tr><td>土</td><td>甘</td><td>土气中和（如脾胃调和）则生甘</td></tr><tr><td>金</td><td>辛</td><td>金气不降（如肺气上逆）则生辛</td></tr><tr><td>水</td><td>咸</td><td>水气下润（如肾水泛滥）则生咸</td></tr></tbody></table><blockquote><p>土作为中气，起着调和五味的作用。当土气不和时，其他四行的味道就会失衡。调和五脏的原动力在于<strong>中宫土气</strong>的平衡。</p></blockquote><h2 id="五行与音律" tabindex="-1">五行与音律 <a class="header-anchor" href="#五行与音律" aria-label="Permalink to &quot;五行与音律&quot;">​</a></h2><table tabindex="0"><thead><tr><th>五行</th><th>五音</th><th>五季</th></tr></thead><tbody><tr><td>土</td><td>宫</td><td>长夏</td></tr><tr><td>金</td><td>商</td><td>秋</td></tr><tr><td>木</td><td>角</td><td>春</td></tr><tr><td>火</td><td>徵</td><td>夏</td></tr><tr><td>水</td><td>羽</td><td>冬</td></tr></tbody></table><hr><blockquote><p><strong>正本清源，传承有道。</strong></p></blockquote>',26)])])}const p=d(h,[["render",o]]);export{u as __pageData,p as default};
